constructorTests = [
    (("size", "0"), ""),
    (("size", "1"), "0"),
    (("bitlist", "(1,1,0,1)"), "1101"),
    (("bitlist", "[1,0,0,1]"), "1001"),
    (("intVal", "5678"), "1011000101110"),
    (("bitstring", "00110011"), "00110011"),
    (("streamobject", "111100001111"), "111100001111"),
    (
        ("filename", testinput1_bits),
        "0100000100100000011010000111010101101110011001110111001001111001",
    ),
    (
        ("filename", testinput2_bits),
        "0100011100000000101011001100011001110110011001010010000001100001",
    ),
    (
        ("filename", testinput3_bits),
        "0100100100100000011010000110000101110110011001010010000001100001",
    ),
    (
        ("filename", testinput4_bits),
        "0100000100100000011010000111010101101110011001110111001001111001",
    ),
    (
        ("filename", testinput5_bits),
        "0100000100100000011010000111010101101110011001110111001001111001",
    ),
    (
        ("filename", testinput6_bits),
        "1101010011000111100111111010001101101110011001110111001001111001",
    ),
    (
        ("filename", testinput7_bits),
        "0110010011100010111000101100000100010101010000001100011000001001",
    ),
]


class ConstructorTestCases(unittest.TestCase):
    def testConstructors(self):
        for args, expected in constructorTests:
            mode = args[0]
            if mode == "size":
                bitvec = BitVector.BitVector(size=eval(args[1]))
            elif mode == "bitlist":
                bitvec = BitVector.BitVector(bitlist=eval(args[1]))
            elif mode == "intVal":
                bitvec = BitVector.BitVector(intVal=int(args[1]))
            elif mode == "bitstring":
                assert isinstance(args[1], str)
                bitvec = BitVector.BitVector(bitstring=args[1])
            elif mode == "streamobject":
                assert isinstance(args[1], str)
                fp_read = io.StringIO(args[1])
                bitvec = BitVector.BitVector(fp=fp_read)
            elif mode == "filename":
                assert isinstance(args[1], bytes)
                with tempfile.NamedTemporaryFile(delete=False) as tmp:
                    tmp.write(args[1])
                    tmp_path = tmp.name
                try:
                    bvec = BitVector.BitVector(filename=tmp_path)
                    bitvec = bvec.read_bits_from_file(64)
                    bvec.close_file_object()
                finally:
                    if os.path.exists(tmp_path):
                        os.remove(tmp_path)
            self.assertEqual(str(bitvec), expected)
